import{_ as o,B as s,o as r,c as n,h as t,x as i}from"./chunks/framework.DSnR1BhL.js";const b=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),d={name:"getting-started/index.md"};function l(p,e,h,c,u,g){const a=s("ArchitectureFlow");return r(),n("div",null,[e[0]||(e[0]=t('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Welcome to the Cobalt Design System. This guide will help you get up and running regardless of your role on the product team.</p><h2 id="what-is-cobalt" tabindex="-1">What is Cobalt? <a class="header-anchor" href="#what-is-cobalt" aria-label="Permalink to &quot;What is Cobalt?&quot;">​</a></h2><p>Cobalt is a unified design system that provides reusable components, design tokens, and guidelines to help teams build consistent, accessible, and performant user interfaces. It bridges the gap between design and developers by offering a shared language and toolkit.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Description</th></tr></thead><tbody><tr><td><strong>Consistency</strong></td><td>Every component follows the same visual and interaction patterns across products.</td></tr><tr><td><strong>Accessibility</strong></td><td>All components meet WCAG 2.1 AA standards out of the box.</td></tr><tr><td><strong>Composability</strong></td><td>Components are designed to be combined in flexible ways without breaking.</td></tr><tr><td><strong>Performance</strong></td><td>Lightweight web components with minimal runtime overhead.</td></tr><tr><td><strong>Theming</strong></td><td>Default light and dark themes today, with a token structure ready for more themes.</td></tr></tbody></table><h2 id="choose-your-path" tabindex="-1">Choose Your Path <a class="header-anchor" href="#choose-your-path" aria-label="Permalink to &quot;Choose Your Path&quot;">​</a></h2><p>Cobalt serves designers, developers, and product managers. Pick the guide that fits your role to get the most relevant onboarding experience.</p><h3 id="for-designers" tabindex="-1">For Designers <a class="header-anchor" href="#for-designers" aria-label="Permalink to &quot;For Designers&quot;">​</a></h3><p>Learn how to use the Cobalt Figma library, apply design tokens in your mockups, and hand off specs to developers with confidence.</p><p><a href="./designers.html">Read the Designers Guide</a></p><h3 id="for-developers" tabindex="-1">For Developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to &quot;For Developers&quot;">​</a></h3><p>Install packages, set up your framework of choice, import components, and start building. Covers vanilla HTML, React, Vue, and Angular.</p><p><a href="./developers.html">Read the Developers Guide</a></p><h3 id="for-product-managers" tabindex="-1">For Product Managers <a class="header-anchor" href="#for-product-managers" aria-label="Permalink to &quot;For Product Managers&quot;">​</a></h3><p>Understand what the design system provides, how to request new components, and the governance model that keeps Cobalt evolving.</p><p><a href="./product-managers.html">Read the Product Managers Guide</a></p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Cobalt flows from design tokens through themed web components into framework-native wrappers:</p>',19)),i(a),e[1]||(e[1]=t(`<h3 id="style-dictionary-tokens" tabindex="-1">Style Dictionary tokens <a class="header-anchor" href="#style-dictionary-tokens" aria-label="Permalink to &quot;Style Dictionary tokens&quot;">​</a></h3><p>The foundation of Cobalt is a single source of truth for design decisions, authored in the <a href="https://tr.designtokens.org/format/" target="_blank" rel="noreferrer">DTCG</a> format and transformed by <a href="https://styledictionary.com/" target="_blank" rel="noreferrer">Style Dictionary</a>.</p><p><strong>DTCG</strong> stands for the <a href="https://www.designtokens.org/" target="_blank" rel="noreferrer">Design Tokens Community Group</a>, a W3C community group defining an open, vendor-neutral standard for how design tokens are structured and serialized. The format prescribes a predictable JSON shape — each token carries a <code>$value</code>, <code>$type</code>, and optional <code>$description</code> — plus a reference syntax (<code>{color.brand.500}</code>) for aliasing tokens to other tokens.</p><p>This matters because it turns tokens into portable data: Figma, PenPot, Tokens Studio, Style Dictionary, and any future tool that speaks DTCG can read and write the same files without a custom adapter. It future-proofs the pipeline against tool churn and lets design and developers share one canonical definition of every value.</p><p>From one set of DTCG JSON files we generate CSS custom properties, SCSS variables, JS/TS exports, and a flat JSON reference so designers, developers, and tooling all consume the same values. A three-tier structure (primitive → semantic → component) keeps raw palette values out of components and makes theming a matter of swapping semantic mappings.</p><h3 id="lit-based-web-components" tabindex="-1">Lit-based web components <a class="header-anchor" href="#lit-based-web-components" aria-label="Permalink to &quot;Lit-based web components&quot;">​</a></h3><p>Components are built on <a href="https://lit.dev/" target="_blank" rel="noreferrer">Lit</a>, a thin layer over the native Web Components APIs. This gives us standards-based custom elements that run in any modern browser without a framework runtime — the output is just HTML tags like <code>&lt;co-button&gt;</code>. Lit keeps bundles small, supports declarative templates and reactive properties, and lets us ship a single component library that stays portable across frameworks, server-rendered pages, and vanilla HTML.</p><h3 id="framework-wrappers" tabindex="-1">Framework wrappers <a class="header-anchor" href="#framework-wrappers" aria-label="Permalink to &quot;Framework wrappers&quot;">​</a></h3><p>To make the web components feel native in each ecosystem, Cobalt publishes thin auto-generated wrappers for <strong>React</strong>, <strong>Vue</strong>, and <strong>Angular</strong>, derived from the Custom Elements Manifest. Each wrapper exposes idiomatic props, events, and types for its framework — <code>onClick</code> handlers in React, <code>v-model</code> and kebab-cased events in Vue, and Angular&#39;s <code>CUSTOM_ELEMENTS_SCHEMA</code> integration — while delegating all rendering and behavior to the underlying Lit element. One implementation, three first-class developer experiences.</p><p>Cobalt is distributed as a set of scoped npm packages:</p><table tabindex="0"><thead><tr><th>Package</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@cobalt/tokens</code></td><td>Design tokens (colors, spacing, typography, etc.) as CSS custom properties and JS objects.</td></tr><tr><td><code>@cobalt/components</code></td><td>Web components built with Lit, usable in any framework.</td></tr><tr><td><code>@cobalt/icons</code></td><td>SVG icon library with tree-shakable exports.</td></tr><tr><td><code>@cobalt/utils</code></td><td>Shared utilities for focus management, ID generation, and more.</td></tr></tbody></table><h2 id="quick-install" tabindex="-1">Quick Install <a class="header-anchor" href="#quick-install" aria-label="Permalink to &quot;Quick Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes tokyo-night github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#C0CAF5;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#9ECE6A;--shiki-light:#032F62;"> add</span><span style="--shiki-dark:#9ECE6A;--shiki-light:#032F62;"> @cobalt/components</span><span style="--shiki-dark:#9ECE6A;--shiki-light:#032F62;"> @cobalt/tokens</span></span></code></pre></div><p>Then import the token stylesheet and any components you need:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes tokyo-night github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#7DCFFF;--shiki-light:#D73A49;">import</span><span style="--shiki-dark:#89DDFF;--shiki-light:#032F62;"> &#39;</span><span style="--shiki-dark:#9ECE6A;--shiki-light:#032F62;">@cobalt/tokens/css</span><span style="--shiki-dark:#89DDFF;--shiki-light:#032F62;">&#39;</span><span style="--shiki-dark:#89DDFF;--shiki-light:#24292E;">;</span></span>
<span class="line"><span style="--shiki-dark:#7DCFFF;--shiki-light:#D73A49;">import</span><span style="--shiki-dark:#89DDFF;--shiki-light:#032F62;"> &#39;</span><span style="--shiki-dark:#9ECE6A;--shiki-light:#032F62;">@cobalt/components/button</span><span style="--shiki-dark:#89DDFF;--shiki-light:#032F62;">&#39;</span><span style="--shiki-dark:#89DDFF;--shiki-light:#24292E;">;</span></span></code></pre></div><blockquote><p><strong>Tip:</strong> You do not need to install <code>@cobalt/tokens</code> separately if you are already using <code>@cobalt/components</code> — tokens are included as a dependency. The explicit install is only needed if you want tokens without the component library.</p></blockquote>`,16))])}const k=o(d,[["render",l]]);export{b as __pageData,k as default};
